// src/components/ForecastTable.jsx
import React from "react";
import NumberInput from "./NumberInput";

function ForecastTable({ rows, setRows }) {
  const handleChange = (index, field, value) => {
    const copy = [...rows];
    copy[index] = { ...copy[index], [field]: value };
    setRows(copy);
  };

  const handleAddRow = () => {
    setRows([
      ...rows,
      { product_id: 1, grade_pack_id: 1, forecast_qty: 0 }
    ]);
  };

  const handleRemoveRow = (index) => {
    setRows(rows.filter((_, i) => i !== index));
  };

  return (
    <div>
      <button onClick={handleAddRow}>Add Row</button>

      <table className="pp-table">
        <thead>
          <tr>
            <th>Product</th>
            <th>Grade/Pack</th>
            <th>Forecast Qty</th>
            <th />
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              <td>
                <NumberInput
                  value={r.product_id}
                  onChange={(v) => handleChange(i, "product_id", v)}
                />
              </td>
              <td>
                <NumberInput
                  value={r.grade_pack_id}
                  onChange={(v) => handleChange(i, "grade_pack_id", v)}
                />
              </td>
              <td>
                <NumberInput
                  value={r.forecast_qty}
                  onChange={(v) => handleChange(i, "forecast_qty", v)}
                />
              </td>
              <td>
                <button onClick={() => handleRemoveRow(i)}>X</button>
              </td>
            </tr>
          ))}
          {rows.length === 0 && (
            <tr>
              <td colSpan={4}>No forecast lines for this period</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default ForecastTable;
